using UnityEngine;
using UnityEngine.Rendering;
using UnityEngine.Rendering.Universal;

public class PostProcessingExample : MonoBehaviour
{
    public Volume volume;
    public VolumeProfile profile;

    // Volume components
    private Bloom bloom;
    private ChromaticAberration chromaticAberration;
    private ColorAdjustments colorAdjustments;
    private Vignette vignette;
    private DepthOfField depthOfField;

    void Start()
    {
        // Get or create Volume
        if (volume == null)
        {
            volume = GetComponent<Volume>();
            if (volume == null)
            {
                volume = gameObject.AddComponent<Volume>();
            }
        }

        // Set up profile
        if (profile != null)
        {
            volume.profile = profile;
        }

        // Try to get post-processing components
        if (volume.profile != null)
        {
            volume.profile.TryGet(out bloom);
            volume.profile.TryGet(out chromaticAberration);
            volume.profile.TryGet(out colorAdjustments);
            volume.profile.TryGet(out vignette);
            volume.profile.TryGet(out depthOfField);
        }

        Debug.Log("Post-processing initialized!");
    }

    void Update()
    {
        // Example: Toggle effects with keys
        if (Input.GetKeyDown(KeyCode.Alpha1))
        {
            ToggleBloom();
        }
        if (Input.GetKeyDown(KeyCode.Alpha2))
        {
            ToggleVignette();
        }
        if (Input.GetKeyDown(KeyCode.Alpha3))
        {
            ToggleChromaticAberration();
        }

        // Example: Damage effect
        if (Input.GetKeyDown(KeyCode.H))
        {
            ShowDamageEffect();
        }

        // Example: Speed effect
        if (Input.GetKeyDown(KeyCode.LeftShift))
        {
            ShowSpeedEffect();
        }
    }

    // --- Effect Control ---
    public void EnableBloom(float intensity = 0.5f)
    {
        if (bloom != null)
        {
            bloom.active = true;
            bloom.intensity.value = intensity;
        }
    }

    public void DisableBloom()
    {
        if (bloom != null)
        {
            bloom.active = false;
        }
    }

    public void ToggleBloom()
    {
        if (bloom != null)
        {
            bloom.active = !bloom.active;
            Debug.Log("Bloom: " + bloom.active);
        }
    }

    public void EnableVignette(float intensity = 0.5f)
    {
        if (vignette != null)
        {
            vignette.active = true;
            vignette.intensity.value = intensity;
        }
    }

    public void DisableVignette()
    {
        if (vignette != null)
        {
            vignette.active = false;
        }
    }

    public void ToggleVignette()
    {
        if (vignette != null)
        {
            vignette.active = !vignette.active;
        }
    }

    public void EnableChromaticAberration(float intensity = 0.5f)
    {
        if (chromaticAberration != null)
        {
            chromaticAberration.active = true;
            chromaticAberration.intensity.value = intensity;
        }
    }

    public void DisableChromaticAberration()
    {
        if (chromaticAberration != null)
        {
            chromaticAberration.active = false;
        }
    }

    public void ToggleChromaticAberration()
    {
        if (chromaticAberration != null)
        {
            chromaticAberration.active = !chromaticAberration.active;
        }
    }

    // --- Game event effects ---
    public void ShowDamageEffect()
    {
        Debug.Log("Damage effect!");

        // Red vignette
        EnableVignette(0.8f);
        if (vignette != null)
        {
            vignette.color.value = Color.red;
        }

        // Chromatic aberration
        EnableChromaticAberration(0.8f);

        // Reset after delay
        Invoke("ResetEffects", 0.3f);
    }

    public void ShowSpeedEffect()
    {
        Debug.Log("Speed effect!");

        // Bloom
        EnableBloom(1f);

        // Color adjustment
        if (colorAdjustments != null)
        {
            colorAdjustments.active = true;
            colorAdjustments.saturation.value = 50f;
        }

        // Reset after delay
        Invoke("ResetEffects", 0.5f);
    }

    public void ResetEffects()
    {
        DisableBloom();
        DisableVignette();
        DisableChromaticAberration();

        if (colorAdjustments != null)
        {
            colorAdjustments.active = false;
            colorAdjustments.saturation.value = 0f;
        }

        Debug.Log("Effects reset!");
    }
}

